// Default checklist for a site, by its type. Auditors can switch in the UI.
export const TYPE_TEMPLATE = {
  'Materials Recovery Facility': 'mrf',
  'Hauling Yard': 'hauling',
  'Operations Yard': 'hauling',
  'Transfer Station': 'hauling',
  'Landfill': 'hauling',
  'Compost / Organics': 'hauling',
  'Office / Other': 'facility',
}

export const templateKeyForType = (type) => TYPE_TEMPLATE[type] || 'hauling'

export const TEMPLATE_LIST = Object.entries(AUDIT_TEMPLATES).map(([key, t]) => ({ key, title: t.title }))

export function templateItemCount(key) {
  const t = AUDIT_TEMPLATES[key]
  return t ? t.sections.reduce((n, s) => n + s.items.length, 0) : 0
}

